mapper.select:
SELECT COALESCE(MAX(version_no), 0)
FROM merchant_page_config_version
WHERE

    merchant_id = #{merchantId}


    merchant_id IS NULL

  AND page_type = #{pageType}

mapper.delete:
DELETE FROM merchant_page_config_version
WHERE id NOT IN (
    SELECT id FROM (
        SELECT id FROM merchant_page_config_version
        WHERE

            merchant_id = #{merchantId}


            merchant_id IS NULL

          AND page_type = #{pageType}
        ORDER BY version_no DESC
        LIMIT #{keepCount}
    ) AS keep_ids
)
AND

    merchant_id = #{merchantId}


    merchant_id IS NULL

AND page_type = #{pageType}
